function formattaNumero(num, anno) { return String(num).padStart(5, "0") + "-" + anno; }
function giornoRelativo(offsetGiorni) {
  const d = new Date(); d.setHours(0, 0, 0, 0); d.setDate(d.getDate() + offsetGiorni);
  return d.toISOString().slice(0, 10);
}
function giorniAllaScadenza(iso) {
  if (!iso) return null;
  const oggi = new Date(); oggi.setHours(0, 0, 0, 0);
  return Math.round((new Date(iso + "T00:00:00") - oggi) / 86400000);
}
function scadenzaInfo(iso, stato) {
  const g = giorniAllaScadenza(iso);
  if (g === null || stato === "consegnato") return null;
  if (g < 0)  return { testo: `In ritardo di ${Math.abs(g)}g`, livello: "rosso" };
  if (g === 0) return { testo: "Scade oggi", livello: "rosso" };
  if (g <= 3) return { testo: `Scade tra ${g}g`, livello: "giallo" };
  return { testo: `Scade tra ${g}g`, livello: "ok" };
}
function formattaScadenza(iso) {
  if (!iso) return "—";
  return new Date(iso + "T00:00:00").toLocaleDateString("it-IT", { day: "2-digit", month: "short", year: "numeric" });
}

function iconaDispositivo(tipo) {
  const p = { size: 20, strokeWidth: 1.8 };
  switch (tipo) {
    case "Smartphone": return <Smartphone {...p} />;
    case "Laptop":     return <Laptop {...p} />;
    case "Tablet":     return <Tablet {...p} />;
    case "Audio":      return <Headphones {...p} />;
    case "Console":    return <Gamepad2 {...p} />;
    default:           return <Wrench {...p} />;
  }
}

