const STORICO_MENSILE = [];

// Salvataggio permanente sul dispositivo. In ambienti dove lo storage è
// disattivato (es. anteprima protetta) ricade su una copia in memoria, così
// l'app non va in errore; una volta online sul dispositivo salva davvero.
const STORE_KEY = "rigenialab_v1";
const memFallback = {};
const safeStore = {
  get(key) {
    try { const v = window.localStorage.getItem(key); return v == null ? null : JSON.parse(v); }
    catch (e) { return key in memFallback ? memFallback[key] : null; }
  },
  set(key, val) {
    try { window.localStorage.setItem(key, JSON.stringify(val)); }
    catch (e) { memFallback[key] = val; }
  },
};
function usePersistentState(subKey, initial) {
  const full = STORE_KEY + ":" + subKey;
  const [val, setVal] = useState(() => {
    const saved = safeStore.get(full);
    return saved == null ? initial : saved;
  });
  useEffect(() => { safeStore.set(full, val); }, [full, val]);
  return [val, setVal];
}

